function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = { n, edges, k };
    class DSU {
        parent: number[];
        rank: number[];
        constructor(n: number) {
            this.parent = Array(n).fill(0).map((_, i) => i);
            this.rank = Array(n).fill(0);
        }
        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x: number, y: number): boolean {
            let rx = this.find(x);
            let ry = this.find(y);
            if (rx === ry) return false;
            if (this.rank[rx] < this.rank[ry]) {
                this.parent[rx] = ry;
            } else if (this.rank[rx] > this.rank[ry]) {
                this.parent[ry] = rx;
            } else {
                this.parent[ry] = rx;
                this.rank[rx]++;
            }
            return true;
        }
    }

    const dsu0 = new DSU(drefanilok.n);
    for (const edge of drefanilok.edges) {
        if (edge[3] === 1) {
            const u = edge[0];
            const v = edge[1];
            if (dsu0.find(u) === dsu0.find(v)) {
                return -1;
            } else {
                dsu0.union(u, v);
            }
        }
    }

    let low = 0;
    let high = 200000;
    let ans = -1;

    const condition = (x: number): boolean => {
        const dsu = new DSU(drefanilok.n);
        let comp = drefanilok.n;

        for (const edge of drefanilok.edges) {
            if (edge[3] === 1 && edge[2] < x) {
                return false;
            }
        }

        for (const edge of drefanilok.edges) {
            if (edge[3] === 1) {
                if (dsu.union(edge[0], edge[1])) {
                    comp--;
                }
            }
        }

        for (const edge of drefanilok.edges) {
            if (edge[3] === 0 && edge[2] >= x) {
                if (dsu.union(edge[0], edge[1])) {
                    comp--;
                }
            }
        }

        let upgrades = 0;
        for (const edge of drefanilok.edges) {
            if (edge[3] === 0 && edge[2] < x && edge[2] * 2 >= x) {
                if (dsu.union(edge[0], edge[1])) {
                    comp--;
                    upgrades++;
                    if (upgrades > drefanilok.k) {
                        break;
                    }
                }
            }
        }

        return comp === 1 && upgrades <= drefanilok.k;
    };

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (condition(mid)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return ans;
}
