function check(x: number, n: number, edges: number[][], k: number): boolean {
    const dsu = new DSU(n);
    let countPaid = 0;

    for (const edge of edges) {
        const [u, v, s, must] = edge;
        if (must === 1) {
            if (s < x) {
                return false;
            }
            dsu.union(u, v);
        }
    }

    const freeEdges: number[][] = [];
    const paidEdges: number[][] = [];

    for (const edge of edges) {
        const [u, v, s, must] = edge;
        if (must === 0) {
            if (s >= x) {
                freeEdges.push(edge);
            } else if (2 * s >= x) {
                paidEdges.push(edge);
            }
        }
    }

    for (const edge of freeEdges) {
        dsu.union(edge[0], edge[1]);
    }

    for (const edge of paidEdges) {
        const [u, v, s, must] = edge;
        if (dsu.find(u) !== dsu.find(v)) {
            dsu.union(u, v);
            countPaid++;
            if (countPaid > k) {
                break;
            }
        }
    }

    return dsu.components === 1 && countPaid <= k;
}
